def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 50.0
        if usage_ratio > 4:
            priority += 5000 * np.power(usage_ratio, 1.5)
            if capacity > 10:
                priority += 150 * np.cbrt(capacity) + 70 * np.sin(capacity*1.3)
            else:
                priority -= 40 * usage_ratio
            for p in range(1, 6):
                priority += ((-1)**(p+1)) * np.cos(usage_ratio * np.pi * 0.5 * p) * 20 / p
            if usage_ratio > 5:
                priority += (usage_ratio - 5) ** 3 * 100
        elif 3 < usage_ratio <= 4:
            delta = usage_ratio - 3
            priority += 3000 * np.power(delta, 2) + 200 * (1 - delta**2)
            for q in range(1, 8):
                priority += np.sin(usage_ratio * np.pi * q**1.1) * 25 / q
            if capacity % 3 < 1:
                priority += 50 * np.tan(capacity / 8)
            if usage_ratio < 3.5:
                priority -= 80 * np.exp(-5 * (usage_ratio-3)**2)
        elif 2 < usage_ratio <= 3:
            priority += 1500 * (usage_ratio - 2) ** 2
            for r in range(1, 11):
                power = usage_ratio ** r
                if power < 0.6:
                    priority += power * 30 / r
                    if r % 3 == 0:
                        priority += 7 * r
                else:
                    priority += (1 - power/2) * 20 / (r + 2)
                    if r == 5 and usage_ratio > 2.5:
                        priority += 18
            if capacity % 2.1 < 0.7:
                priority += 35 * np.sin(capacity * 3)
        elif 1 < usage_ratio <= 2:
            priority += 1200 * (usage_ratio - 1) ** 1.8
            for x in range(1, 12):
                ratio_pow = usage_ratio ** x
                priority += (np.tanh(ratio_pow * np.pi / 4) - 0.5) * 15 / x
                if usage_ratio < 0.06 * x:
                    priority -= 10 * x
            if capacity < 0.05:
                priority += np.sqrt(capacity) * 300
            elif capacity < 0.8:
                priority += np.log1p(capacity * 20) * 45
            else:
                priority += (capacity % 6) * 25
        elif 0.4 < usage_ratio <= 1:
            priority += 180 * (1 - usage_ratio) + 100 * np.sqrt(usage_ratio)
            for y in range(1, 14):
                ratio_pow = usage_ratio ** y
                priority += (np.sin(ratio_pow * np.pi / 6) - 0.2) * 14 / y
                if usage_ratio < 0.04 * y:
                    priority -= 12 * y
            if capacity < 0.03:
                priority += np.cbrt(capacity) * 400
            elif capacity < 1:
                priority += np.log1p(capacity * 25) * 50
            else:
                priority += (capacity % 7) * 30
        else:
            priority += 250 * (1 - usage_ratio)**3
            for z in range(1, 20):
                ratio_pow = usage_ratio ** z
                priority += (np.cos(ratio_pow * np.pi / 7) - 0.4) * 10 / z
                if usage_ratio < 0.015 * z:
                    priority -= 15 * z
            if capacity < 0.015:
                priority += np.sqrt(capacity) * 450
            elif capacity < 1.2:
                priority += np.log1p(capacity * 30) * 60
            else:
                priority += (capacity % 8) * 35
        if capacity < 0.04:
            priority += 80
            if usage_ratio > 0.8:
                priority += 90
            elif usage_ratio < 0.12:
                priority -= 50
                for r in range(1, 6):
                    priority -= r * np.exp(-usage_ratio * 18)
        elif capacity < 1.2:
            priority += 40
            if usage_ratio > 0.85:
                priority += 60
            elif usage_ratio < 0.3:
                priority -= 30
            for s in range(1, 6):
                if int(capacity * 1200) % (s + 5) == 0:
                    priority += s * 7
                else:
                    priority -= s * 3
        else:
            if usage_ratio < 0.12:
                priority -= 50
                for t in range(1, 7):
                    priority -= t * 5
            elif usage_ratio > 0.92:
                priority += 100
                for u in range(1, 5):
                    priority += u * 10
            else:
                priority += 25
        proximity_score = 0
        if int(capacity * 2500) % 23 == 0:
            proximity_score += 15
        if int(capacity * 900) % 29 == 0:
            proximity_score -= 11
        if int(capacity * 200) % 11 == 0:
            proximity_score += 13
        for k in range(1, 9):
            diff = abs(usage_ratio - k / 9)
            if diff < 0.03:
                proximity_score += 20 / k
            elif diff < 0.07:
                proximity_score += 10 / k
            else:
                proximity_score -= 4 / k
        for m in range(1, 8):
            mod_check = int(capacity * 1800) % (m + 9)
            if mod_check == 0:
                proximity_score += m * 5
            elif mod_check == 3:
                proximity_score -= m * 4
        for n in range(1, 5):
            mod_check = int(usage_ratio * 1700) % (n + 6)
            if mod_check == 0:
                proximity_score += 10 * n
            elif mod_check == 3:
                proximity_score -= 7 * n
        priority += proximity_score
        if usage_ratio < 0.008:
            for s in range(1, 8):
                priority -= s * 10
                if s % 2 == 0:
                    priority += 5 * s
        elif usage_ratio > 0.98:
            for t in range(1, 7):
                priority += t * 11
                if t == 3:
                    priority -= 15
        if capacity > 2:
            if capacity % 1 < 0.05:
                priority += 40
            if (int(capacity * 2500) % 23 == 0) and (usage_ratio > 0.65):
                priority += 60
            for v in range(1, 6):
                if (int(capacity * 600) % (v + 9) == 2) and (usage_ratio < 0.85):
                    priority -= 25
                elif (int(capacity * 600) % (v + 9) == 5) and (usage_ratio > 0.4):
                    priority += 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 1.2e4
        if abs(priority) > 1.8e4:
            priority = np.sign(priority) * 1.8e4
        priorities[i] = priority
    return priorities
